import { useState } from "react";
import { useForm } from "react-hook-form";
import { addRepaymentPlan } from "../services/debtService";

const RepaymentPlan = ({
  debtId,
  show,
  onClose
}) => {

  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState("");

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors }
  } = useForm();

  const onSubmit = async (data) => {

    const request = {
      id: 0,
      debtId: debtId,
      monthlyPaymentAmount: parseFloat(
        data.monthlyPaymentAmount
      ),
      dateStarted: data.dateStarted
    };

    try {



      const result = await addRepaymentPlan(request);

      if (result > 0) {

        setMessage(
          "Payment plan added successfully"
        );

        setMessageType("success");

        reset();

        // close modal after short delay
        setTimeout(() => {

          setMessage("");

          onClose();

        }, 1500);

      } else {

        setMessage(
          "Failed to add payment plan"
        );

        setMessageType("danger");
      }

    } catch {

      setMessage("Error calling API");

      setMessageType("danger");
    }
  };

  // do not render modal if closed
  if (!show) {
    return null;
  }

  return (
    <>
      {/* Backdrop */}
      <div
        className="modal-backdrop fade show"
      ></div>

      {/* Modal */}
      <div
        className="modal fade show d-block"
        tabIndex="-1"
        role="dialog"
      >
        <div className="modal-dialog">
          <div className="modal-content">

            {/* Header */}
            <div className="modal-header">

              <h5 className="modal-title">
                Add Repayment Plan
              </h5>

              <button
                type="button"
                className="btn-close"
                onClick={onClose}
              ></button>

            </div>

            {/* Body */}
            <div className="modal-body">

              {/* Success/Error Message */}
              {message && (
                <div
                  className={`alert alert-${messageType}`}
                >
                  {message}
                </div>
              )}

              <form
                onSubmit={handleSubmit(onSubmit)}
              >

                {/* Monthly Payment Amount */}
                <div className="mb-3">

                  <label className="form-label">
                    Monthly Payment Amount
                  </label>

                  <input
                    type="number"
                    step="0.01"
                    className="form-control"
                    {...register(
                      "monthlyPaymentAmount",
                      {
                        required:
                          "Monthly payment amount is required",
                        min: {
                          value: 1,
                          message:
                            "Amount must be greater than 0"
                        }
                      }
                    )}
                  />

                  {errors.monthlyPaymentAmount && (
                    <div className="text-danger">
                      {
                        errors
                          .monthlyPaymentAmount
                          .message
                      }
                    </div>
                  )}

                </div>

                {/* Date Started */}
                <div className="mb-3">

                  <label className="form-label">
                    Date Started
                  </label>

                  <input
                    type="date"
                    className="form-control"
                    {...register("dateStarted", {
                      required:
                        "Date started is required"
                    })}
                  />

                  {errors.dateStarted && (
                    <div className="text-danger">
                      {errors.dateStarted.message}
                    </div>
                  )}

                </div>

                {/* Footer */}
                <div className="modal-footer">

                  <button
                    type="submit"
                    className="btn btn-primary"
                  >
                    Add
                  </button>

                  <button
                    type="button"
                    className="btn btn-secondary"
                    onClick={onClose}
                  >
                    Close
                  </button>

                </div>

              </form>

            </div>

          </div>
        </div>
      </div>
    </>
  );
};

export default RepaymentPlan;
